def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        penalty = 0
        complexity = 1
        if ratio < 0.5:
            for x in range(1, 5):
                penalty += ((ratio ** x) * (np.sin(x * np.pi * ratio))) / (x ** 2)
            complexity = 20
        elif 0.5 <= ratio <= 1:
            for y in range(1, 7):
                factor = (-1) ** y
                penalty += factor * (np.cos(y * np.pi * ratio) / (y + 1))
            complexity = 10
            if ratio > 0.75:
                extra = 0
                for z in range(1, 4):
                    extra += (np.exp(-z * (1 - ratio)) / (z ** 1.5))
                penalty += extra * 3
        else:
            for a in range(1, 4):
                for b in range(1, 4):
                    penalty += ((ratio ** (a * b)) / (a + b)) * ((-1) ** (a + b))
            complexity = 30
            if ratio > 2:
                priorities[i] = np.inf
                continue
        base_score = abs(ratio) * complexity
        adjusted_score = base_score + penalty
        if adjusted_score < 0:
            adjusted_score = abs(adjusted_score) / (complexity / 2)
        if np.isinf(adjusted_score) or np.isnan(adjusted_score):
            priorities[i] = np.inf
        else:
            priorities[i] = adjusted_score
    return priorities
